const item = $input.first().json;

const systemPrompt = `Kamu adalah Master Copywriter yang menulis template pesan untuk BOT Customer Service.

PERAN PENTING: Template yang kamu tulis adalah pesan yang akan DIKIRIM OLEH BOT CS KEPADA PELANGGAN.
Kamu BUKAN pelanggan. Kamu MENULIS pesan dari sudut pandang CS/Admin yang MENJAWAB pertanyaan pelanggan.

TUGAS: Buat ${item.count} variasi template BALASAN BOT CS untuk intent: "${item.intent}".
Deskripsi situasi: ${item.desc}
Gaya Bahasa: ${item.gaya}

CONTOH BENAR (BOT CS menjawab pelanggan):
"Halo Kak {nama_pelanggan}! Terima kasih sudah menghubungi {nama_bisnis}. Ada yang bisa kami bantu hari ini?"

CONTOH SALAH (ini sudut pandang pelanggan, JANGAN seperti ini):
"Halo, saya ingin bertanya tentang jadwal kelas"

=== ATURAN AGNOSTIC (WAJIB) ===
1. DILARANG mengarang nama bisnis, produk, harga, atau data spesifik apapun!
2. Gunakan PLACEHOLDER kurung kurawal:
   {nama_pelanggan}, {nama_bisnis}, {nama_jasa}, {nama_paket}, {harga}, {link_daftar}, {jam_operasional}, {lokasi}, {kontak_admin}
3. Untuk data dari Knowledge Base, gunakan KURUNG SIKU:
   [RAG: sebutkan 3 benefit utama], [RAG: jelaskan profil tim], [RAG: sebutkan testimoni]
4. Setiap variasi harus punya pendekatan psikologis BERBEDA.
5. Panjang: 2-5 kalimat (cocok chat).

=== FORMAT OUTPUT ===
LANGSUNG tulis JSON array. JANGAN tulis kata pembuka, penjelasan, atau komentar apapun.
[
  {
    "name": "Nama strategi",
    "content": "Isi pesan BOT CS disini...",
    "category": "${item.category}",
    "sub_category": "${item.intent}"
  }
]`;

return [{
  json: {
    intent: item.intent,
    category: item.category,
    count: item.count,
    systemPrompt,
    userPrompt: `Tulis ${item.count} template pesan BOT CS (bukan pesan pelanggan) untuk intent "${item.intent}". LANGSUNG output JSON array tanpa pembuka.`
  }
}];

const raw = $input.first().json.text || $input.first().json.response?.text || $input.first().json.output || '';
const intent = $('Build Agnostic Prompt').first().json.intent;
const category = $('Build Agnostic Prompt').first().json.category;

// Step 1: Strip everything before the first [ bracket
let jsonStr = raw.trim();

// Remove markdown code fences if present
jsonStr = jsonStr.replace(/```(?:json)?\s*/g, '').replace(/```/g, '');

// Find the actual JSON array
const arrStart = jsonStr.indexOf('[');
const arrEnd = jsonStr.lastIndexOf(']');
if (arrStart !== -1 && arrEnd !== -1 && arrEnd > arrStart) {
  jsonStr = jsonStr.substring(arrStart, arrEnd + 1);
}

let templates = [];
try {
  const parsed = JSON.parse(jsonStr);
  // Normalize keys: LLM may use 'template' instead of 'content'
  templates = parsed.map(t => ({
    name: t.name || t.title || t.strategy || 'Unnamed',
    content: t.content || t.template || t.text || t.message || '',
    category: category,
    sub_category: intent
  }));
  // Filter out empty content
  templates = templates.filter(t => t.content.length > 10);
} catch(e) {
  // Fallback: put raw text as single template
  templates = [{
    name: 'Parse Error - ' + intent,
    content: raw.substring(0, 1000),
    category: category,
    sub_category: intent
  }];
}

return [{
  json: {
    intent,
    count: templates.length,
    templates
  }
}];

// Collect all parsed templates from every loop iteration
const items = $input.all();
const form = $('Input Gaya Bahasa').first().json;
const gaya = form['Gaya Bahasa'];
const botId = form['Bot ID'] || null;

let allTemplates = [];
let summary = [];

for (const item of items) {
  const tpls = item.json.templates || [];
  allTemplates.push(...tpls);
  summary.push(`${item.json.intent}: ${tpls.length} variasi`);
}

const output = {
  meta: {
    generator: 'Template Generator V3 — Agnostic',
    gaya_bahasa: gaya,
    bot_id: botId,
    total_templates: allTemplates.length,
    total_intents: items.length,
    generated_at: new Date().toISOString()
  },
  templates: allTemplates
};

const fileName = `agnostic_templates_${new Date().toISOString().slice(0,10)}.json`;
const jsonString = JSON.stringify(output, null, 2);

return [{
  json: {
    fileName,
    totalTemplates: allTemplates.length,
    totalIntents: items.length,
    botId,
    summary: summary.join('\n'),
    preview: allTemplates.slice(0, 3).map(t => `[${t.sub_category}] ${t.name}`).join(', ')
  },
  binary: {
    data: {
      data: Buffer.from(jsonString, 'utf-8').toString('base64'),
      mimeType: 'application/json',
      fileName
    }
  }
}];
